const genData = (obj) => {
  const data=[]; const now=new Date();
  for(let i=29;i>=0;i--){const date=new Date(now);date.setDate(date.getDate()-i);const ds=date.toISOString().split("T")[0];const dow=(date.getDay()+6)%7;const o=obj[dow]||3000;const ca_ttc=Math.round(o*(0.7+Math.random()*0.6));const ca_ht=Math.round(ca_ttc/1.1);const ta=Math.round(ca_ht*(0.2+Math.random()*0.15));const invoices=[];const n=2+Math.floor(Math.random()*4);const frs=["Metro","Rungis Express","Transgourmet","Pomona","Brake France","Davigel"];let rem=ta;for(let j=0;j<n;j++){const amt=j===n-1?rem:Math.round(rem*(0.2+Math.random()*0.4));rem-=amt;invoices.push({id:ds+"-"+j,fournisseur:frs[Math.floor(Math.random()*frs.length)],montant:Math.max(amt,50),categorie:CATEGORIES[Math.floor(Math.random()*CATEGORIES.length)],date:ds});}data.push({date:ds,ca:ca_ttc,ca_ht,objectif:o,invoices});}return data;
};

